	.TITLE	RASTER	.PROC	M680002		; mnmonics CALM 2	.RADIX	10.		; base 10 par dfaut	.HEX			; listing en hexadcima	.REF	SM8		; df diverses	.REF	NTREL		; df noyau temps rel	.REF	GESMEM		; df gestionnaire de mmoire	.REF	FOS		; df file operating system	.REF	LIB		; df librairie	.REF	DRIVERS		; df driversSM100	=	0; Variables; ---------	.LOC	0OFLAGS:	.BLKB	2		; flags diversOBUDIS:	.BLKB	30		; buffer write displayOLUPTS:	.BLKB	4		; ^matrice du lutinOLUPTC:	.BLKB	4		; ^matrice du fondOLUPTF:	.BLKB	4		; ^fond de l'cranOLUPTO:	.BLKB	4		; ^pour oprationsOLUOLD:	.BLKB	4		; ancienne positionOLUNEW:	.BLKB	4		; nouvelle positionOLUORI:	.BLKB	4		; origine du mouvementOLULGY:	.BLKB	2		; hauteur du lutinOLULGX:	.BLKB	2		; largeur du lutinOLUIYF:	.BLKB	2		; Iy pour OLUPTFOLUIYO:	.BLKB	2		; Iy pour OLUPTOLGVAR:; Programme; ---------	.LOC	0START:	.W	LIB,?OPELIB	; ouvre la librairie	LOAD.B	D3,#2	.W	LIB,?MOUSE	LOAD.L	D4,#LGVAR	.W	GESMEM,?GETMEM	; demande mmoire pour var.	JUMP,NE	ER	LOAD.L	A6,A4		; A6 <-- ^variables	CLR.B	(A6)+OFLAGS	; clear tous les flagsJUMP ESSAI	; <<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<	LOAD.L	A3,#R16"MOTIF	CLR.L	D3	LOAD.W	D5,#H'4	LOAD.W	D4,#50	SWAP.W	D4	LOAD.W	D4,#2	LOAD.W	D2,#16	SWAP.W	D2	LOAD.W	D2,#16-1	LOAD.B	D1,#INVDOT	CALL	RASTMD	LOAD.W	D3,#50	SWAP.W	D3	LOAD.W	D3,#2	LOAD.W	D4,#50	SWAP.W	D4	LOAD.W	D4,#32	LOAD.W	D2,#16	SWAP.W	D2	LOAD.W	D2,#16-1	LOAD.B	D1,#INVDOT	CALL	RASTDD	LOAD.W	D3,#50	SWAP.W	D3	LOAD.W	D3,#32	LOAD.W	D4,#50	SWAP.W	D4	LOAD.W	D4,#100	LOAD.W	D2,#16	SWAP.W	D2	LOAD.W	D2,#16-1	LOAD.B	D1,#INVDOT	CALL	RASTDD	LOAD.W	D3,#50	SWAP.W	D3	LOAD.W	D3,#100	LOAD.W	D4,#50	SWAP.W	D4	LOAD.W	D4,#129	LOAD.W	D2,#16	SWAP.W	D2	LOAD.W	D2,#16-1	LOAD.B	D1,#INVDOT	CALL	RASTDD	.W	LIB,?GETCAR	COMP.B	D3,#'1	JUMP,EQ	50$	COMP.B	D3,#'2	JUMP,EQ	ESSAI10$:	LOAD.L	A3,#R16"MOTIF	CLR.L	D3	LOAD.W	D5,#H'4	LOAD.W	D4,#100	SWAP.W	D4	LOAD.W	D4,#020$:	LOAD.W	D2,#16	SWAP.W	D2	LOAD.W	D2,#16-1	LOAD.B	D1,#INVDOT	CALL	RASTMD	.W	LIB,?GETCAR	COMP.B	D3,#END	JUMP,EQ	RETOUR	LOAD.W	D2,#16	SWAP.W	D2	LOAD.W	D2,#16-1	LOAD.B	D1,#INVDOT	CALL	RASTMD	INC.W	D4	SWAP.W	D4	INC.W	D4	SWAP.W	D4	JUMP	20$50$:	LOAD.L	A3,#R16"MOTIF	CLR.L	D3	LOAD.W	D5,#H'4	LOAD.W	D4,#100	SWAP.W	D4	LOAD.W	D4,#260$:	LOAD.W	D2,#16	SWAP.W	D2	LOAD.W	D2,#16-1	LOAD.B	D1,#INVDOT	CALL	RASTMD	PUSH.L	D3	.W	LIB,?GETCAR	LOAD.W	D0,D3	POP.L	D3	COMP.B	D0,#END	JUMP,EQ	RETOUR	LOAD.W	D2,#16	SWAP.W	D2	LOAD.W	D2,#16-1	LOAD.B	D1,#INVDOT	CALL	RASTMD	INC.W	D3	COMP.W	D3,#8	JUMP,LO	60$	CLR.W	D3	JUMP	60$ER:	PUSH.W	D7		; sauve l'erreur	.W	LIB,?AFCR	; passe  la ligne	POP.W	D7		; reprend l'erreur	.W	LIB,?AFERROR	; affiche l'erreur	.W	LIB,?GETCAR	; attend une toucheRETOUR:	LOAD.B	D3,#EOP	.W	LIB,?AFCAR	; efface toute la fentre	.W	LIB,?CLOLIB	; ferme la librairie	.W	FOS,?STOP	; avorte le processus ...ESSAI:	LOAD.B	D3,#AFCCMO	.W	LIB,?AFCAR	LOAD.W	D3,#0	SWAP.W	D3	LOAD.W	D3,#50	LOAD.W	D4,#350	SWAP.W	D4	LOAD.W	D4,#0	LOAD.W	D2,#SETDOT	.W	LIB,?DRSEG	LOAD.L	D3,#-1	LOAD.L	D4,#-1	.W	LIB,?DRMDEF	LOAD.W	D3,#100	SWAP.W	D3	LOAD.W	D3,#100	LOAD.W	D4,#80	SWAP.W	D4	LOAD.W	D4,#80	LOAD.W	D2,#SETDOT	.W	LIB,?DRMATRIX	LOAD.L	D3,#H'AA55AA55	LOAD.L	D4,#H'AA55AA55	.W	LIB,?DRMDEF	LOAD.W	D3,#100	SWAP.W	D3	LOAD.W	D3,#200	LOAD.W	D4,#80	SWAP.W	D4	LOAD.W	D4,#80	LOAD.W	D2,#SETDOT	.W	LIB,?DRMATRIX	LOAD.L	D3,#H'AAAAAAAA	LOAD.L	D4,#H'AAAAAAAA	.W	LIB,?DRMDEF	LOAD.W	D3,#200	SWAP.W	D3	LOAD.W	D3,#100	LOAD.W	D4,#80	SWAP.W	D4	LOAD.W	D4,#80	LOAD.W	D2,#SETDOT	.W	LIB,?DRMATRIX	LOAD.L	D3,#H'88002200	LOAD.L	D4,#H'88002200	.W	LIB,?DRMDEF	LOAD.W	D3,#200	SWAP.W	D3	LOAD.W	D3,#200	LOAD.W	D4,#80	SWAP.W	D4	LOAD.W	D4,#80	LOAD.W	D2,#SETDOT	.W	LIB,?DRMATRIX	LOAD.W	D4,#50	SWAP.W	D4	LOAD.W	D4,#50	CLR.W	D010$:	LOAD.B	D1,D0	INC.B	D1	LOAD.L	A4,#R16"MOTS1	LOAD.L	A3,#R16"MOTC1	DEC.B	D1	JUMP,EQ	15$	LOAD.L	A4,#R16"MOTS2	LOAD.L	A3,#R16"MOTC2	DEC.B	D1	JUMP,EQ	15$	LOAD.L	A4,#R16"MOTS5	LOAD.L	A3,#R16"MOTC5	DEC.B	D1	JUMP,EQ	15$	LOAD.L	A4,#R16"MOTS4	LOAD.L	A3,#R16"MOTC4	DEC.B	D1	JUMP,EQ	15$	LOAD.L	A4,#R16"MOTS3	LOAD.L	A3,#R16"MOTC3	DEC.B	D1	JUMP,EQ	15$	LOAD.L	A4,#R16"MOTS3	LOAD.L	A3,#R16"MOTC31	DEC.B	D1	JUMP,EQ	15$	CLR.W	D0	JUMP	10$15$:	CALL	FSPRITE		; dessine le premier	JUMP,NE	ER20$:	.W	LIB,?GETKEY	TEST.L	D3:#BKPSEUDO	JUMP,BS	20$	COMP.W	D3,#END	JUMP,EQ	RETOUR	COMP.W	D3,#KEYMGP	JUMP,EQ	50$	COMP.W	D3,#KEYMPO	JUMP,NE	20$	.W	LIB,?IFMOUSE	JUMP,NE	20$	SWAP.W	D4	ADD.W	D4,#16	SWAP.W	D4	CALL	MSPRITE		; dplace	JUMP	20$50$:	CALL	LSPRITE		; efface le dernier	INC.W	D0	JUMP	10$;--------\; FSPRITE >;========/; Dessine le premier lutin.; in	D4.L	premire coordonne;	A4.L	^matrice du lutin (set);	A3.L	^matrice du fond (clear); out	D7.W	erreur; mod	D7.WFSPRITE:	PUSHM.L	D0..D6,A3,A4	LOAD.L	(A6)+OLUOLD,D4	LOAD.W	D7,#ERDIIL	; D7 <-- illgal	LOAD.B	D0,(A4)+0	COMP.B	D0,(A3)+0	; mme largeur ?	JUMP,NE	90$		; non => 90$	LOAD.B	D0,(A4)+1	COMP.B	D0,(A3)+1	; mme hauteur ?	JUMP,NE	90$		; non => 90$	ADD.L	A4,#2	LOAD.L	(A6)+OLUPTS,A4	; mm. ^matrice du lutin	SUB.L	A4,#2	ADD.L	A3,#2	LOAD.L	(A6)+OLUPTC,A3	; mm. ^matrice du fond	SUB.L	A3,#2	CLR.L	D0	LOAD.B	D0,(A4)+1	; D0 <-- hauteur du lutin	LOAD.W	(A6)+OLULGY,D0	LOAD.B	D0,(A4)+0	; D0 <-- largeur du lutin	LOAD.W	(A6)+OLULGX,D0	ADD.W	D0,#8-1	SR.W	D0,#3		; D0 <-- largeur en bytes	LOAD.W	(A6)+OLUIYF,D0	SL.W	D0,#1	LOAD.W	(A6)+OLUIYO,D0	LOAD.W	D4,(A6)+OLUIYF	MUL.WU	D4,(A6)+OLULGY	LOAD.L	D0,D4	MUL.WU	D4,#1+4	LOAD.W	D1,#MTYPCP	; D1 <-- type compte mmoire	.W	GESMEM,?GETMEM	; demande mmoire tampon	JUMP,NE	90$	LOAD.L	(A6)+OLUPTF,A4	; mm ^pour fond de l'cran	ADD.L	A4,D0	LOAD.L	(A6)+OLUPTO,A4	; mm ^pour oprations	LOAD.L	D3,(A6)+OLUOLD	LOAD.L	A4,(A6)+OLUPTF	CLR.L	D4	LOAD.W	D6,(A6)+OLUIYF	LOAD.L	D2,(A6)+OLULGY	LOAD.B	D1,#SETDOT	CALL	RASTCLR	CALL	RASTDM		; sauve le fond	LOAD.L	A3,(A6)+OLUPTC	CLR.L	D3	LOAD.W	D5,(A6)+OLUIYF	LOAD.L	D4,(A6)+OLUOLD	LOAD.B	D1,#CLRDOT	CALL	RASTMD		; dessine le fond du motif	LOAD.L	A3,(A6)+OLUPTS	LOAD.B	D1,#SETDOT	CALL	RASTMD		; dessine le contenu du motif	CLR.W	D7		; D7 <-- ok90$:	POPM.L	D0..D6,A3,A4	TEST.W	D7		; retour EQ/NE	RET;--------\; MSPRITE >;========/; Dplace un lutin.; in	D4.L	nouvelle coordonne; out	-; mod	-MSPRITE:	PUSHM.L	D1..D6,A3,A4	LOAD.L	(A6)+OLUNEW,D4	LOAD.W	D3,(A6)+OLUOLD+0 ; D3 <-- Y le plus petit	LOAD.W	D1,(A6)+OLUNEW+0	COMP.W	D3,D1	JUMP',LS 10$	EX.L	D3,D1		; D3 <-- Y le plus petit10$:	SUB.W	D1,D3		; D1 <-- |diffrence|	SWAP.W	D3	LOAD.W	D4,(A6)+OLUOLD+2 ; D4 <-- X le plus petit	LOAD.W	D2,(A6)+OLUNEW+2	COMP.W	D4,D2	JUMP',LS 15$	EX.L	D4,D2		; D4 <-- X le plus petit15$:	SUB.W	D2,D4		; D2 <-- |diffrence|	LOAD.W	D3,D4	COMP.W	D2,(A6)+OLULGX	; intersection avec l'ancien ?	JUMP,HS	50$		; non => 50$	COMP.W	D1,(A6)+OLULGY	JUMP,HS	50$	ADD.W	D2,(A6)+OLULGX	; D2 <-- largeur	ADD.W	D1,(A6)+OLULGY	; D1 <-- hauteur	SWAP.W	D2	LOAD.W	D2,D1	SWAP.W	D2		; D2 <-- hauteur/largeur	LOAD.L	(A6)+OLUORI,D3	LOAD.L	A4,(A6)+OLUPTO	CLR.L	D4	LOAD.W	D6,(A6)+OLUIYO	LOAD.B	D1,#SETDOT	CALL	RASTCLR	CALL	RASTDM		; cran --> buffer oprations	PUSH.L	D2	LOAD.L	D2,(A6)+OLULGY	LOAD.L	A3,(A6)+OLUPTS	CLR.L	D3	LOAD.W	D5,(A6)+OLUIYF	LOAD.L	A4,(A6)+OLUPTO	LOAD.W	D4,(A6)+OLUOLD+0	SUB.W	D4,(A6)+OLUORI+0	SWAP.W	D4	LOAD.W	D4,(A6)+OLUOLD+2	SUB.W	D4,(A6)+OLUORI+2	LOAD.W	D6,(A6)+OLUIYO	LOAD.B	D1,#CLRDOT	CALL	RASTMM		; efface le motif	LOAD.L	A3,(A6)+OLUPTF	CLR.L	D3	LOAD.W	D5,(A6)+OLUIYF	LOAD.B	D1,#SETDOT	CALL	RASTMM		; remet le fond	LOAD.L	A3,(A6)+OLUPTO	LOAD.W	D3,(A6)+OLUNEW+0	SUB.W	D3,(A6)+OLUORI+0	SWAP.W	D3	LOAD.W	D3,(A6)+OLUNEW+2	SUB.W	D3,(A6)+OLUORI+2	LOAD.W	D5,(A6)+OLUIYO	LOAD.L	A4,(A6)+OLUPTF	CLR.L	D4	LOAD.W	D6,(A6)+OLUIYF	LOAD.B	D1,#SETDOT	CALL	RASTCLR	CALL	RASTMM		; sauve le nouveau fond	LOAD.L	D4,D3	LOAD.L	A3,(A6)+OLUPTC	CLR.L	D3	LOAD.W	D5,(A6)+OLUIYF	LOAD.L	A4,(A6)+OLUPTO	LOAD.W	D6,(A6)+OLUIYO	LOAD.B	D1,#CLRDOT	CALL	RASTMM		; met le fond du nouveau motif	LOAD.L	A3,(A6)+OLUPTS	LOAD.B	D1,#SETDOT	CALL	RASTMM		; met le contenu du nouveau motif	POP.L	D2	LOAD.L	D3,(A6)+OLUORI	CLR.L	D4	LOAD.B	D1,#INVDOT	CALL	RASTDM		; xor avec l'cran (astuce)	EX.L	D3,D4	EX.L	A3,A4	EX.L	D5,D6	CALL	RASTMD		; remet dans l'cran	JUMP	80$50$:	LOAD.L	D2,(A6)+OLULGY	LOAD.L	D3,(A6)+OLUOLD	LOAD.L	A4,(A6)+OLUPTF	CLR.L	D4	LOAD.W	D6,(A6)+OLUIYF	LOAD.B	D1,#INVDOT	CALL	RASTDM		; xor avec l'cran (astuce)	EX.L	A3,A4	EX.L	D3,D4	EX.L	D5,D6	CALL	RASTMD		; remet l'ancien fond dans l'cran	LOAD.L	D3,(A6)+OLUNEW	LOAD.L	A4,(A6)+OLUPTF	CLR.L	D4	LOAD.W	D6,(A6)+OLUIYF	LOAD.B	D1,#SETDOT	CALL	RASTCLR	CALL	RASTDM		; sauve le fond	LOAD.L	A3,(A6)+OLUPTC	CLR.L	D3	LOAD.W	D5,(A6)+OLUIYF	LOAD.L	D4,(A6)+OLUNEW	LOAD.B	D1,#CLRDOT	CALL	RASTMD		; dessine le fond du nouveau motif	LOAD.L	A3,(A6)+OLUPTS	LOAD.B	D1,#SETDOT	CALL	RASTMD		; dessine le contenu du nouveau motif80$:	LOAD.L	(A6)+OLUOLD,(A6)+OLUNEW	POPM.L	D1..D6,A3,A4	RET;--------\; LSPRITE >;========/; Efface le dernier lutin.; in	-; out	D7.W	erreur; mod	D7.WLSPRITE:	PUSHM.L	D1..D6,A3,A4	LOAD.L	A3,(A6)+OLUPTS	CLR.L	D3	LOAD.W	D5,(A6)+OLUIYF	LOAD.L	D4,(A6)+OLUOLD	LOAD.L	D2,(A6)+OLULGY	LOAD.B	D1,#CLRDOT	CALL	RASTMD		; efface le lutin	LOAD.L	A3,(A6)+OLUPTF	LOAD.B	D1,#SETDOT	CALL	RASTMD		; remet le fond	LOAD.L	A4,(A6)+OLUPTF	; A4 <-- ^dbut tranche mmoire	LOAD.W	D1,#MTYPCP	; D1 <-- type compte mmoire	.W	GESMEM,?GIVMEM	; rend la mmoire	POPM.L	D1..D6,A3,A4	TEST.W	D7		; retour EQ/NE	RET;--------\; RASTCLR >;========/; Efface (rempli de zro) la destination.; in	A4.L	^mmoire destination;	D6.W	Iy destination;	D2.L	hauteur/largeur (dy;dx); out	-; mod	-RASTCLR:	PUSHM.L	D0,D1,D2,A3,A4	LOAD.W	D1,D2	ADD.W	D1,#7	SR.W	D1,#3		; D1 <-- largeur en bytes	DEC.W	D1		; D1 <--  cause du test NMO	SWAP.W	D2		; D2 <-- hauteur en points	DEC.W	D2		; D2 <--  cause du test NMO30$:	LOAD.L	A3,A4	LOAD.W	D0,D140$:	CLR.B	(A3+)		; efface une ligne	DECJ.W,NMO D0,40$	ADD.W	A4,D6		; A4 <-- ^ligne en dessous	DECJ.W,NMO D2,30$	POPM.L	D0,D1,D2,A3,A4	RET;--------\; RASTMM  >;========/; Dplace une surface rectangulaire mmoire --> mmoire.; in	----;	A3.L	^mmoire source;	D3.L	coordonne source (y;x);	D5.W	Iy source;	----;	A4.L	^mmoire destination;	D4.L	coordonne destination (y;x);	D6.W	Iy destination;	----;	D2.L	hauteur/largeur (dy;dx);	D1.B	opration (SETDOT/CLRDOT/INVDOT); out	-; mod	-RASTMM:	PUSHM.L	D3,A3,A0	LOAD.L	A0,A3	LOAD.L	A3,#(A6)+OBUDIS+1	LOAD.B	(A3)+0,#DRAWRASTER	SWAP.W	D3	LOAD.L	(A3)+1,D3	; <xx> <yy>	SWAP.W	D3	LOAD.L	(A3)+5,A0	; <pppp>	LOAD.W	(A3)+9,D5	; <iy>	SWAP.W	D4	LOAD.L	(A3)+11,D4	; <xx> <yy>	SWAP.W	D4	LOAD.L	(A3)+15,A4	; <pppp>	LOAD.W	(A3)+19,D6	; <iy>	SWAP.W	D2	LOAD.L	(A3)+21,D2	; <dx> <dy>	SWAP.W	D2	LOAD.B	(A3)+25,D1	; <m>	LOAD.L	D3,#26	.W	LIB,?STRING	POPM.L	D3,A3,A0	RET;--------\; RASTMD  >;========/; Dplace une surface rectangulaire mmoire --> cran.; in	----;	A3.L	^mmoire source;	D3.L	coordonne source (y;x);	D5.W	Iy source;	----;	D4.L	coordonne destination (y;x);	----;	D2.L	hauteur/largeur (dy;dx);	D1.B	opration (SETDOT/CLRDOT/INVDOT); out	-; mod	-RASTMD:	PUSHM.L	D3,A3,A0	LOAD.L	A0,A3	LOAD.L	A3,#(A6)+OBUDIS+1	LOAD.B	(A3)+0,#DRAWRASTER	SWAP.W	D3	LOAD.L	(A3)+1,D3	; <xx> <yy>	SWAP.W	D3	LOAD.L	(A3)+5,A0	; <pppp>	LOAD.W	(A3)+9,D5	; <iy>	SWAP.W	D4	LOAD.L	(A3)+11,D4	; <xx> <yy>	SWAP.W	D4	CLR.L	(A3)+15		; <pppp>	CLR.W	(A3)+19		; <iy>	SWAP.W	D2	LOAD.L	(A3)+21,D2	; <dx> <dy>	SWAP.W	D2	LOAD.B	(A3)+25,D1	; <m>	LOAD.L	D3,#26	.W	LIB,?STRING	POPM.L	D3,A3,A0	RET;--------\; RASTDM  >;========/; Dplace une surface rectangulaire cran --> mmoire.; in	----;	D3.L	coordonne source (y;x);	----;	A4.L	^mmoire destination;	D4.L	coordonne destination (y;x);	D6.W	Iy destination;	----;	D2.L	hauteur/largeur (dy;dx);	D1.B	opration (SETDOT/CLRDOT/INVDOT); out	-; mod	-RASTDM:	PUSHM.L	D3,A3	LOAD.L	A3,#(A6)+OBUDIS+1	LOAD.B	(A3)+0,#DRAWRASTER	SWAP.W	D3	LOAD.L	(A3)+1,D3	; <xx> <yy>	SWAP.W	D3	CLR.L	(A3)+5		; <pppp>	CLR.W	(A3)+9		; <iy>	SWAP.W	D4	LOAD.L	(A3)+11,D4	; <xx> <yy>	SWAP.W	D4	LOAD.L	(A3)+15,A4	; <pppp>	LOAD.W	(A3)+19,D6	; <iy>	SWAP.W	D2	LOAD.L	(A3)+21,D2	; <dx> <dy>	SWAP.W	D2	LOAD.B	(A3)+25,D1	; <m>	LOAD.L	D3,#26	.W	LIB,?STRING	POPM.L	D3,A3	RET;--------\; RASTDD  >;========/; Dplace une surface rectangulaire cran --> cran.; in	----;	D3.L	coordonne source (y;x);	----;	D4.L	coordonne destination (y;x);	----;	D2.L	hauteur/largeur (dy;dx);	D1.B	opration (SETDOT/CLRDOT/INVDOT); out	-; mod	-RASTDD:	PUSHM.L	D3,A3	LOAD.L	A3,#(A6)+OBUDIS+1	LOAD.B	(A3)+0,#DRAWRASTER	SWAP.W	D3	LOAD.L	(A3)+1,D3	; <xx> <yy>	SWAP.W	D3	CLR.L	(A3)+5		; <pppp>	CLR.W	(A3)+9		; <iy>	SWAP.W	D4	LOAD.L	(A3)+11,D4	; <xx> <yy>	SWAP.W	D4	CLR.L	(A3)+15		; <pppp>	CLR.W	(A3)+19		; <iy>	SWAP.W	D2	LOAD.L	(A3)+21,D2	; <dx> <dy>	SWAP.W	D2	LOAD.B	(A3)+25,D1	; <m>	LOAD.L	D3,#26	.W	LIB,?STRING	POPM.L	D3,A3	RETMOTIF:	.B	B'00000111,B'11000000,B'11111111,B'00000000	.B	B'00000111,B'01000000,B'11111111,B'00000000	.B	B'00000111,B'01100000,B'11111110,B'00000000	.B	B'00001000,B'00010000,B'11111110,B'00000000	.B	B'00010000,B'00001000,B'11111100,B'00000000	.B	B'00100000,B'00000100,B'11111100,B'00000000	.B	B'01000000,B'00000010,B'11111000,B'00000000	.B	B'10000000,B'00000001,B'11111000,B'00000000	.B	B'10000000,B'00000001,B'11110000,B'00000000	.B	B'01000000,B'00000010,B'11110000,B'00000000	.B	B'00100000,B'00000100,B'11100000,B'00000000	.B	B'00010000,B'00001000,B'11100000,B'00000000	.B	B'00001000,B'00010000,B'11000000,B'00000000	.B	B'00000100,B'01100000,B'11000000,B'00000000	.B	B'00000010,B'01000000,B'10000000,B'00000000	.B	B'00000001,B'1100